/*
 * atanf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly atanf  (test_atanf_opt.elf)
 *   2. Linked with toolchain's default atanf        (test_atanf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifdef EN_PERF
static volatile float g_acc;
#endif

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;   /* prevent constant-folding of literal arguments */
    g_acc += atanf(vx);
#else
    float r = atanf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* 100 representative test points                                      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf -> pi/2 */
    emit_u(0xff800000u);  /* -Inf -> -pi/2 */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal: -2^-149 */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN);                /* 2^-126, smallest normal */
    emit(-FLT_MIN);               /* -2^-126 */
    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    emit_u(0x7f7fffffu);          /* FLT_MAX */
    emit_u(0xff7fffffu);          /* -FLT_MAX */
    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 ULP neighbors (8) --- */
    emit_u(0x3f7fffffu);          /* one ULP below 1.0 */
    emit(1.0f);                   /* 1.0: atan = pi/4 */
    emit_u(0x3f800001u);          /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);          /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);          /* a few ULPs above 1.0 */
    emit(-1.0f);                  /* -1.0: atan = -pi/4 */
    emit_u(0xbf7fffffu);          /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u);          /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3f000000u);          /* 0.5 */
    emit_u(0x3effffffu);          /* one ULP below 0.5 */
    emit_u(0x3f000001u);          /* one ULP above 0.5 */
    emit_u(0x40000000u);          /* 2.0 */
    emit_u(0x3fffffffu);          /* one ULP below 2.0 */
    emit_u(0x40000001u);          /* one ULP above 2.0 */

    /* --- Section 6: Inverse trig canonical constants (14) --- */
    /* atan(0.5) ~ 0.4636, atan(1) = pi/4, atan(sqrt(3)) = pi/3, etc. */
    emit(0.5f);                   /* atan = pi/6 approx? no: atan(1/sqrt(3))=pi/6 */
    emit(-0.5f);
    emit_u(0x3f490fdbu);          /* pi/4 ~ 0.7854: atan(tan(pi/4))=pi/4 */
    emit_u(0xbf490fdbu);          /* -pi/4 */
    emit_u(0x3fc90fdbu);          /* pi/2 ~ 1.5708 */
    emit_u(0xbfc90fdbu);          /* -pi/2 */
    emit_u(0x40490fdbu);          /* pi ~ 3.1416 */
    emit_u(0xc0490fdbu);          /* -pi */
    emit_u(0x3f279a74u);          /* 1/sqrt(3) ~ 0.5774: atan = pi/6 */
    emit_u(0xbf279a74u);          /* -1/sqrt(3) */
    emit_u(0x3fb504f3u);          /* sqrt(3) ~ 1.7321: atan = pi/3 */
    emit_u(0xbfb504f3u);          /* -sqrt(3) */
    emit(10.0f);                  /* large: atan approaches pi/2 */
    emit(-10.0f);

    /* --- Section 7: Large argument saturation (8) --- */
    emit(100.0f);
    emit(-100.0f);
    emit(1000.0f);
    emit(-1000.0f);
    emit(1.0e7f);
    emit(-1.0e7f);
    emit(1.0e10f);
    emit(-1.0e10f);

    /* --- Section 8: ULP neighbors of key atan output boundaries (15) --- */
    /* atan saturates to +-pi/2; transitions at x=+-1 (pi/4) and x=+-tan(pi/8) ~ 0.4142 */
    /* triplets around x=1 at bit level */
    emit_u(0x3f7ffffd u);         /* 3 ULP below 1.0 */
    emit_u(0x3f7ffffeu);          /* 2 ULP below 1.0 */
    emit_u(0x3f800002u);          /* 2 ULP above 1.0 */
    /* triplets around x=-1 */
    emit_u(0xbf7ffffdu);          /* 3 ULP toward zero from -1.0 */
    emit_u(0xbf7ffffeu);          /* 2 ULP toward zero from -1.0 */
    emit_u(0xbf800002u);          /* 2 ULP away from zero from -1.0 */
    /* triplets around x=tan(pi/8) ~ 0.4142 = sqrt(2)-1 */
    emit_u(0x3ed413ccu);          /* sqrt(2)-1 ~ 0.41421: one ULP below */
    emit_u(0x3ed413cdu);          /* sqrt(2)-1 exact float */
    emit_u(0x3ed413ceu);          /* sqrt(2)-1 one ULP above */
    /* triplets around x=-tan(pi/8) */
    emit_u(0xbed413ccu);          /* -tan(pi/8) one ULP toward zero */
    emit_u(0xbed413cdu);          /* -tan(pi/8) exact */
    emit_u(0xbed413ceu);          /* -tan(pi/8) one ULP away from zero */
    /* around x=tan(3*pi/8) ~ 2.4142 = sqrt(2)+1 */
    emit_u(0x401a827au);          /* sqrt(2)+1 ~ 2.4142 one ULP below */
    emit_u(0x401a827bu);          /* sqrt(2)+1 exact float */
    emit_u(0x401a827cu);          /* sqrt(2)+1 one ULP above */

    /* --- Section 9: Small-argument fast-path thresholds (8) --- */
    /* Many impls use atan(x)~x for |x| below some threshold */
    emit_u(0x39800000u);          /* 2^-12: small arg fast path */
    emit_u(0xb9800000u);          /* -2^-12 */
    emit_u(0x3c000000u);          /* 2^-7 */
    emit_u(0xbc000000u);          /* -2^-7 */
    emit_u(0x34000000u);          /* 2^-24: near machine epsilon */
    emit_u(0xb4000000u);          /* -2^-24 */
    emit(1.0e-20f);               /* very tiny */
    emit(-1.0e-20f);

    /* --- Section 10: Polynomial branch and hard cases (22) --- */
    /* atan switches polynomial at |x|=1, |x|=tan(pi/8), |x|=tan(3pi/8) */
    /* Points in each polynomial interval and at transitions */
    emit(0.25f);                  /* interval [0, tan(pi/8)]: interior */
    emit(-0.25f);
    emit(0.125f);
    emit(-0.125f);
    emit(0.75f);                  /* interval [tan(pi/8), 1]: interior */
    emit(-0.75f);
    emit(1.25f);                  /* interval [1, tan(3pi/8)]: interior */
    emit(-1.25f);
    emit(2.0f);                   /* interval [tan(3pi/8), inf]: interior */
    emit(-2.0f);
    emit(3.0f);
    emit(-3.0f);
    /* ULP neighbors of pi/8 output boundary input: tan(pi/8) ~ 0.4142 */
    emit_u(0x3ed413cbu);          /* two ULPs below tan(pi/8) */
    emit_u(0x3ed413cfu);          /* two ULPs above tan(pi/8) */
    /* ULP neighbors of 3*pi/8 output boundary input: tan(3pi/8) ~ 2.4142 */
    emit_u(0x401a8279u);          /* two ULPs below tan(3pi/8) */
    emit_u(0x401a827du);          /* two ULPs above tan(3pi/8) */
    /* half-integers and other representative normals */
    emit(0.1f);
    emit(-0.1f);
    emit(5.0f);
    emit(-5.0f);
    emit(50.0f);
    emit(-50.0f);
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [-pi/4, pi/4] in 200 steps */
static void test_sweep(void)
{
    float pi_4 = 0.78539816339744830962f;
    int nsteps = 200;
    float step = 2.0f * pi_4 / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(-pi_4 + (float)i * step);
}

/* 8. Exhaustive [-pi/4, pi/4] sweep every 65536 ULP */
static void test_exhaustive_small(void)
{
    uint32_t start = 0xbf490fdbu; /* -pi/4 */
    uint32_t end = 0x3f490fdbu;   /* pi/4 */
    for (uint32_t b = start; b <= end; b += 65536) {
        if (b >= start && b <= end)
            emit_u(b);
    }
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

